                        portalAutomatonActive: false,
                        illegalMoveRejected: 0,
                        hazardRejected: 0,
                        falseGoalRejected: 0,
                        filterAxisRejected: 0,
                        portalLegalityRejected: 0,
                        mustCrossImpossibleRejected: 0,
                        adjacencyRejected: 0,
                        mustPassRejected: 0,
                        mustCrossRejected: 0,
                        portalAutomatonRejected: 0,
                        parityRejected: 0,
                        portalParityImpossibleRejected: 0,
                        portalObligationSignatureImpossibleRejected: 0,
