                        const rRatio = l.reqLen > 0 ? Math.max(0, Math.min(1, nLen / l.reqLen)) : 1;
                        const remainsObligations = hasMust || crossNeed > 0 || Math.max(0, l.reqInt - state.ints) > 0;
                        const projectedRevisit = (state.countsArr[searchCtx.keyToIdx(nk)] || 0) > 0;
                        const projectedNonKnot = projectedRevisit && !nextInKnot;
                        const inLateKnotPhases = activePhase === 'knot' || activePhase === 'finish';
                        const projectedIntersections = state.ints + (projectedRevisit ? 1 : 0);
                        const projectedNonKnotIntersections = Math.max(0, projectedIntersections - Math.max(0, state.knotCrossBudget || 0));
                        const shouldEnforceNonKnotCap = inLateKnotPhases
