                        reqInt: Math.max(0, Number(level.reqInt) || 0),
                        portals: Math.max(0, Number(level?.portalMap?.size) || 0),
                        filters: Math.max(0, Number(level?.filterMap?.size) || 0),
                        flippers: Math.max(0, Number(level?.flippingFilterMap?.size) || 0),
                        mustPass: Math.max(0, Number(level?.mustPassKeys?.length) || 0),
