                    rootMoveScores: Array.isArray(attemptResult?.debug?.rootMoveScores) ? attemptResult.debug.rootMoveScores.slice(0, 20) : null,
                    candidateMovesConsidered: Number.isFinite(attemptResult?.debug?.candidateMovesConsidered) ? attemptResult.debug.candidateMovesConsidered : null,
                    progressSamples: Array.isArray(attemptResult?.debug?.progressSamples) ? attemptResult.debug.progressSamples : [],
