                    const diag = buildSearchDiagnostics(attemptResult?.debug || {}, attemptResult?.status || 'unknown');
                    const rootGenerated = Math.max(0, Number(attemptResult?.debug?.rootCandidatesGenerated) || 0);
                    const rootExpanded = Math.max(0, Number(attemptResult?.debug?.rootCandidatesExpanded) || 0);
                    const contradictionPrunes = Math.max(0, Number(attemptResult?.debug?.prune?.mustPassBound) || 0) + Math.max(0, Number(attemptResult?.debug?.prune?.mustCrossBound) || 0);
                    const branchesTried = Math.max(0, Number(attemptResult?.debug?.branchesTried) || 0);
