                    nearClosureRescueLowerBoundThreshold: null,
                    nearClosureRescueProfile: null,
                    mustCrossRescueTriggered: false,
                    mustCrossUnlockProgressEvents: 0,
                    signatureBuildCount: 0,
                    signatureBuildMs: 0,
                    signatureStrictBuildCount: 0,
                    signatureStrictBuildMs: 0,
                    memoStrictCollisions: 0,
                    failMemoChecks: 0,
                    failMemoHits: 0,
                    dominanceMemoChecks: 0,
                    dominanceMemoHits: 0,
